import ldap

def search_user_by_username(ldap_server, base_dn, username):
    try:
        # Initialize the LDAP connection
        l = ldap.initialize(ldap_server)
        
        # Bind to the LDAP server (replace with your credentials)
        l.simple_bind_s('cn=admin,dc=example,dc=com', 'password')
        
        # Define the search filter
        search_filter = f"(uid={username})"
        
        # Perform the search
        result_id = l.search(base_dn, ldap.SCOPE_SUBTREE, search_filter)
        
        # Retrieve the results
        result_set = []
        while 1:
            result_type, result_data = l.result(result_id, 0)
            if not result_data:
                break
            else:
                if result_type == ldap.RES_SEARCH_ENTRY:
                    result_set.append(result_data)
        
        # Close the connection
        l.unbind_s()
        
        return result_set
    
    except ldap.LDAPError as e:
        print(f"LDAP Error: {e}")
        return None

